#!/usr/bin/env python3
"""Generate SFT training data from web-based domain knowledge sources.

Produces ~800 QA/instruction/passage examples across 4 sources:
- CISA StopRansomware (~200)
- Kaspersky SecureList (~200)
- DFIR Report (~200)
- SANS DFIR (~150)
"""

import json
import os
from datetime import datetime, timezone

OUTPUT_DIR = os.path.join(os.path.dirname(__file__), "raw")

SYSTEM_PROMPT = "You are a ransomware forensic analyst with deep expertise in Windows internals and incident response."

GENERATED_AT = "2026-03-17T11:00:00Z"
GENERATOR_MODEL = "claude-opus-4-6"


def make_example(source, source_url, source_section, example_type, topics,
                 prompt_id, user_content, assistant_content):
    return {
        "messages": [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": user_content},
            {"role": "assistant", "content": assistant_content},
        ],
        "metadata": {
            "source": source,
            "source_url": source_url,
            "source_section": source_section,
            "example_type": example_type,
            "topics": topics,
            "generation_prompt_id": prompt_id,
            "generated_at": GENERATED_AT,
            "generator_model": GENERATOR_MODEL,
            "quality_score": None,
        },
    }


def write_jsonl(filename, examples):
    path = os.path.join(OUTPUT_DIR, filename)
    with open(path, "w") as f:
        for ex in examples:
            f.write(json.dumps(ex, ensure_ascii=False) + "\n")
    print(f"  Wrote {len(examples)} examples to {path}")
    return len(examples)


