def main():
    os.makedirs(OUTPUT_DIR, exist_ok=True)

    total = 0

    print("Generating CISA StopRansomware examples...")
    cisa = generate_cisa()
    total += write_jsonl("cisa_stopransomware.jsonl", cisa)

    print("Generating Kaspersky SecureList examples...")
    kaspersky = generate_kaspersky()
    total += write_jsonl("kaspersky_securelist.jsonl", kaspersky)

    print("Generating DFIR Report examples...")
    dfir = generate_dfir_report()
    total += write_jsonl("dfir_report.jsonl", dfir)

    print("Generating SANS DFIR examples...")
    sans = generate_sans()
    total += write_jsonl("sans_dfir.jsonl", sans)

    print(f"\nTotal examples generated: {total}")
    print(f"  CISA:     {len(cisa)}")
    print(f"  Kaspersky:{len(kaspersky)}")
    print(f"  DFIR:     {len(dfir)}")
    print(f"  SANS:     {len(sans)}")


if __name__ == "__main__":
    main()
